function greet(name: string) {
  console.log("Hello, " + name.toUpperCase());
}

greet(null); // Runtime error: Cannot read property 'toUpperCase' of null

function greet(name: string | null) {
  if (name) {
    console.log("Hello, " + name.toUpperCase());
  } else {
    console.log("Hello, guest!");
  }
}

greet(null); // Output: Hello, guest!

function greet(name: string | null) {
  console.log("Hello, " + name!.toUpperCase()); // Will throw if name is null
}

from flask import Flask, jsonify

app = Flask(__name__)

# In-memory user data
users = {
    1: {'name': 'Alice'},
    2: {'name': 'Bob'}
}

@app.route('/users/<int:user_id>')
def get_user(user_id):
    user = users.get(user_id)
    if user:
        return jsonify({'user_id': user_id, 'name': user['name']})
    else:
        return jsonify({'error': 'User not found'}), 404

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

from flask import Flask, jsonify

app = Flask(__name__)

# Sample order data
orders = {
    1: [{'order_id': 101, 'item': 'Book'}],
    2: [{'order_id': 102, 'item': 'Pen'}]
}

@app.route('/orders/<int:user_id>')
def get_orders(user_id):
    user_orders = orders.get(user_id, [])
    return jsonify({'user_id': user_id, 'orders': user_orders})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=6000)

